use libfuzzer_sys::fuzz_target;
use asupersync::http::h2::{Connection, ConnectionConfig};

fuzz_target!(|data: &[u8]| {
    let config = ConnectionConfig {
        continuation_timeout: Duration::from_millis(10), // Fast for fuzzing
        ..Default::default()
    };

    let mut conn = Connection::new_server(config);

    // Feed random frame sequences
    let mut cursor = 0;
    while cursor < data.len() {
        let chunk_size = std::cmp::min(data.len() - cursor, 16384);
        let chunk = &data[cursor..cursor + chunk_size];

        // Should never panic, should gracefully handle malformed input
        let _ = conn.process_bytes(chunk);
        cursor += chunk_size;
    }

    // Force timeout check
    conn.check_all_timeouts();

    // Connection should be in valid state
    assert!(conn.is_consistent());
});
